mapper.insert:
/*Chatmapper.insertChatRoom*/
SELECT nextval('seq_tb_chatroom')::text
INSERT INTO tb_chatroom ( chatroom_id, create_at, create_id, update_at, update_id ) VALUES ( #{chatroomId}, COALESCE(#{createAt}, now()), #{createUid}, COALESCE(#{updateAt}, now()), #{createUid} )

mapper.select:
/* Chatmapper.selectChatRoomPaging : 채팅방 목록 조회 (페이징) */ SELECT tb.chatroom_member_id, tb.chatroom_id, tb.uid, tb.chatroom_name, tb.last_read_at, tb.create_at FROM tb_chatroom_member tb
create_at DESC NULLS LAST
LIMIT #{limit} OFFSET #{offset}

/* Chatmapper.selectChatRoomMembers : 채팅방 멤버 + 유저 정보 조회 */ SELECT m.chatroom_id AS "chatroomId", m.uid AS "uid", m.chatroom_name AS "chatroomName", m.last_read_at AS "lastReadAt", u.user_name AS "userName", u.user_nickname AS "userNickname", u.profile_photo_file_id AS "profilePhotoFileId" FROM tb_chatroom_member m LEFT JOIN tb_user u ON u.uid = m.uid AND u.delete_yn = 'N' WHERE m.delete_yn = 'N' AND m.chatroom_id IN
#{chatroomId}
ORDER BY m.chatroom_id, m.create_at

/* Chatmapper.selectChatMessageList : 채팅 메시지 목록 */ SELECT cm.chat_message_id AS id, cm.chat_message_type_code AS messageType, cm.chat_message_content_type_code AS messageTextType, cm.write_uid AS authorId, cm.chat_message_content AS message, cm.create_at AS createAt, NULL AS deleteMemberIds, cm.appointment_id AS appointmentId FROM tb_chatroom_message cm WHERE cm.chatroom_id = #{chatroomId} AND cm.delete_yn = 'N'
AND cm.create_at > #{since}
ORDER BY cm.create_at DESC

mapper.update:
/* Chatmapper.updateChatRoomMemberLastRead : 채팅방 멤버 읽음 시간 업데이트 */
UPDATE tb_chatroom_member
SET last_read_at = COALESCE(#{lastReadAt}, now())
WHERE chatroom_id = #{chatroomId}
  AND uid = #{uid}
  AND delete_yn = 'N'
